import { defineConfig } from "vitest/config";
import react from "@vitejs/plugin-react";
import path from "path";

export default defineConfig({
  plugins: [react()],
  test: {
    environment: "happy-dom",
    setupFiles: "./vitest.setup.ts",
    globals: true,
    include: [
      // Co-located test files
      "app/**/*.{test,spec}.{ts,tsx}",
      "components/**/*.{test,spec}.{ts,tsx}",
      "hooks/**/*.{test,spec}.{ts,tsx}",
    ],
    alias: {
      "@": path.resolve(__dirname, "./"),
    },
    coverage: {
      provider: "v8",
      reporter: ["text", "html"],
      exclude: ["node_modules/"],
    },
  },
});

import axios, {
  AxiosError,
  AxiosInstance,
  AxiosProgressEvent,
  AxiosRequestConfig,
  AxiosResponse,
} from "axios";
import { getSession, signOut } from "next-auth/react";
import { toast } from "sonner"; // Use Sonner for toast notifications
import { APP_ENV, shouldLogErrors } from "@/lib/utils/environment";

// Define error types for better error handling
export interface ApiErrorResponse {
  message: string;
  code?: string;
  details?: unknown;
}

// Get environment variables
const getApiBaseUrl = () => {
  if (process.env.NEXT_PUBLIC_API_BASE_URL) return process.env.NEXT_PUBLIC_API_BASE_URL;
  console.log("appEnv", APP_ENV);
  // if (APP_ENV === "development") return "https://genai-api-dev.makeitmes.com/api/v1";
  throw new Error("NEXT_PUBLIC_API_BASE_URL must be set for non-development environments");
};

const getWebSocketBaseUrl = () => {
  if (process.env.NEXT_PUBLIC_WEBSOCKET_BASE_URL) return process.env.NEXT_PUBLIC_WEBSOCKET_BASE_URL;
  // if (APP_ENV === "development") return "wss://genai-api-dev.makeitmes.com/ws";
  throw new Error("NEXT_PUBLIC_WEBSOCKET_BASE_URL must be set for non-development environments");
};

export const API_BASE_URL = getApiBaseUrl();
export const WEBSOCKET_BASE_URL = getWebSocketBaseUrl();

// Create a configured instance of axios
const axiosInstance: AxiosInstance = axios.create({
  baseURL: API_BASE_URL,
  timeout: 30000, // 30 seconds default timeout
  headers: {
    "Content-Type": "application/json",
  },
});

// Request interceptor for auth token
axiosInstance.interceptors.request.use(
  async (config) => {
    // For AI operations that might take longer, extend the timeout
    if (config.url?.includes("/ai/")) {
      config.timeout = 60000 * 3; // 3 mins for AI operations
    }

    const session = await getSession();
    const token = session?.accessToken ?? "";
    if (token && config.headers) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error: unknown) => {
    console.error("Request interceptor error:", error);
    return Promise.reject(error);
  },
);

// Response interceptor for error handling
axiosInstance.interceptors.response.use(
  (response) => response,
  (error: AxiosError<ApiErrorResponse>) => {
    // Enhanced error logging
    if (shouldLogErrors()) {
      // console.error("API Error:", {
      //   url: error.config?.url,
      //   status: error.response?.status,
      //   statusText: error.response?.statusText,
      //   message: error.response?.data?.message || error.message,
      // });
    }

    // Handle specific status codes
    if (error.response) {
      const status = error.response.status;

      // Authentication errors
      if (status === 401) {
        console.error("Authentication failed. Please log in again.");

        // Only handle 401 in browser environment
        if (typeof window !== "undefined" && window.location.pathname !== "/auth/signin") {
          // Show toast notification
          toast.error("Your session has expired. Please log in again.");
          // Sign out the user and redirect to login page
          signOut({
            callbackUrl: "/", // Redirect to home page after logout
          });
        }
      }

      // Permission errors
      else if (status === 403) {
        console.error("You don't have permission to access this resource");
      }

      // Rate limiting
      else if (status === 429) {
        console.error("Rate limit exceeded. Please try again later.");
      }
    }

    return Promise.reject(error);
  },
);

// Type-safe wrapper functions
export const apiClient = {
  /**
   * Make a GET request
   */
  get: <T>(url: string, config?: AxiosRequestConfig): Promise<T> =>
    axiosInstance.get<T, AxiosResponse<T>>(url, config).then((response) => response.data),

  /**
   * Make a POST request
   */
  post: <T>(url: string, data?: unknown, config?: AxiosRequestConfig): Promise<T> => {
    // Log the full URL for debugging
    console.log(`[API Request] POST: ${API_BASE_URL}${url}`);
    return axiosInstance
      .post<T, AxiosResponse<T>>(url, data, config)
      .then((response) => response.data);
  },

  /**
   * Make a PUT request
   */
  put: <T>(url: string, data?: unknown, config?: AxiosRequestConfig): Promise<T> =>
    axiosInstance.put<T, AxiosResponse<T>>(url, data, config).then((response) => response.data),

  /**
   * Make a PATCH request
   */
  patch: <T>(url: string, data?: unknown, config?: AxiosRequestConfig): Promise<T> => {
    // Log the full URL for debugging
    console.log(`[API Request] PATCH: ${API_BASE_URL}${url}`);
    return axiosInstance
      .patch<T, AxiosResponse<T>>(url, data, config)
      .then((response) => response.data);
  },

  /**
   * Make a DELETE request
   */
  delete: <T>(url: string, config?: AxiosRequestConfig): Promise<T> => {
    // Log the full URL for debugging
    console.log(`[API Request] DELETE: ${API_BASE_URL}${url}`);
    return axiosInstance.delete<T, AxiosResponse<T>>(url, config).then((response) => response.data);
  },
  /**
   * Upload files with progress tracking
   */
  upload: <T>(
    url: string,
    formData: FormData,
    onUploadProgress?: (progressEvent: AxiosProgressEvent) => void,
    config?: AxiosRequestConfig,
  ): Promise<T> =>
    axiosInstance
      .post<T, AxiosResponse<T>>(url, formData, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
        onUploadProgress,
        ...config,
      })
      .then((response) => response.data),
};

export default axiosInstance;

import Cookies from "js-cookie";

// Global environment configuration
export const APP_ENV = process.env.NEXT_PUBLIC_APP_ENV ?? "development";

// Environment check utilities
export const isQAEnvironment = () => APP_ENV === "qa";
export const isDevelopment = () => APP_ENV === "development";
export const isProduction = () => APP_ENV === "production";

// Tracking should only be enabled in production AND with user consent
export const isTrackingEnabled = () => {
  if (!isProduction()) return false;
  const trackingConsent = Cookies.get("styls_tracking_consent");
  console.log("Tracking consent cookie:", trackingConsent);
  return trackingConsent?.includes("essentials") && trackingConsent?.includes("true");
};

// Logging utilities
export const shouldLogErrors = () => APP_ENV === "development" || APP_ENV === "qa";
export const shouldLogDebug = () => APP_ENV === "development";

// Environment display helpers
export const getEnvironmentDisplayName = () => {
  switch (APP_ENV) {
    case "qa":
      return "QA";
    case "development":
      return "Development";
    case "production":
      return "Production";
    case "staging":
      return "Staging";
    default:
      return APP_ENV;
  }
};

console.log(`🌍 Environment: ${getEnvironmentDisplayName()} (${APP_ENV})`);
console.log(`📊 Tracking enabled: ${isTrackingEnabled()}`);

