import { render, screen, fireEvent } from "@testing-library/react";
import { describe, it, expect, vi, beforeEach } from "vitest";
import Navbar from "../index";

// Mock next/link
vi.mock("next/link", () => ({
  __esModule: true,
  default: ({ children, href }: { children: React.ReactNode; href: string }) => (
    <a href={href}>{children}</a>
  ),
}));

// Mock the AuthContext
const mockLogout = vi.fn();
vi.mock("@/context/AuthContext", () => ({
  useAuth: () => ({
    logout: mockLogout,
  }),
}));

// Mock ModeToggle component
vi.mock("@/components/ModeToggle", () => ({
  ModeToggle: () => <button>Toggle theme</button>,
}));

describe("Navbar", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("renders the navigation bar", () => {
    render(<Navbar />);
    expect(screen.getByRole("navigation")).toBeInTheDocument();
  });

  it("renders the mode toggle", () => {
    render(<Navbar />);
    expect(screen.getByText("Toggle theme")).toBeInTheDocument();
  });

  it("renders user avatar with fallback", () => {
    render(<Navbar />);
    expect(screen.getByText("U")).toBeInTheDocument();
  });

  it("renders dropdown trigger button", () => {
    render(<Navbar />);
    const avatarButton = screen.getByRole("button", { name: "U" });
    expect(avatarButton).toBeInTheDocument();
    expect(avatarButton).toHaveAttribute("aria-haspopup", "menu");
  });

  it("dropdown button can be clicked", () => {
    render(<Navbar />);
    const avatarButton = screen.getByRole("button", { name: "U" });
    fireEvent.click(avatarButton);
    // Just verify the button exists and can be clicked without errors
    expect(avatarButton).toBeInTheDocument();
  });
});

import { render, screen, fireEvent } from "@testing-library/react";
import { describe, it, expect, vi, beforeEach } from "vitest";
import Sidebar from "../index";
import { SidebarProvider } from "@/components/ui/sidebar"; // Import the provider

// Mock next/navigation and next/image
vi.mock("next/navigation", () => ({
  usePathname: () => "/sketch",
}));
vi.mock("next/image", () => ({
  __esModule: true,
  default: (props: any) => <img {...props} />,
}));

// Mock localStorage
beforeEach(() => {
  vi.stubGlobal("localStorage", {
    getItem: vi.fn(() => JSON.stringify({ username: "testuser" })),
    setItem: vi.fn(),
    removeItem: vi.fn(),
    clear: vi.fn(),
  });
});

function renderWithProvider() {
  return render(
    <SidebarProvider>
      <Sidebar />
    </SidebarProvider>,
  );
}

describe("Sidebar", () => {
  it("renders sidebar navigation items", () => {
    renderWithProvider();
    expect(screen.getByText(/Sketch to Render/i)).toBeInTheDocument();
    expect(screen.getByText(/2D Sketch/i)).toBeInTheDocument();
    expect(screen.getByText(/Precise Editing/i)).toBeInTheDocument();
    expect(screen.getByText(/Virtual Trial/i)).toBeInTheDocument();
    expect(screen.getByText(/Seamless Prints/i)).toBeInTheDocument();
    expect(screen.getByText(/Product Design/i)).toBeInTheDocument();
    expect(screen.getByText(/Background Change/i)).toBeInTheDocument();
    expect(screen.getByText(/Apply Print/i)).toBeInTheDocument();
    expect(screen.getByText(/Video Generation/i)).toBeInTheDocument();
  });

  it("shows the user's username if present in localStorage", () => {
    renderWithProvider();
    expect(screen.getByText("testuser")).toBeInTheDocument();
  });

  it("toggles sidebar open/close when button is clicked", () => {
    renderWithProvider();
    const toggleButton = screen.getByRole("button", { name: /collapse sidebar|expand sidebar/i });
    fireEvent.click(toggleButton);
    expect(toggleButton).toBeInTheDocument();
  });
});

