"use client";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { ReactNode, useState } from "react";
import { AxiosError } from "axios";

/**
 * Props for the ReactQueryProvider component
 */
interface ReactQueryProviderProps {
  readonly children: ReactNode;
}

/**
 * Global QueryClient instance for use in stores and non-component code
 */
export let queryClient: QueryClient;

/**
 * Provider component for React Query
 * Configures the QueryClient with optimized defaults
 */
export default function ReactQueryProvider({ children }: ReactQueryProviderProps) {
  const [client] = useState(
    () =>
      new QueryClient({
        defaultOptions: {
          queries: {
            staleTime: 5 * 60 * 1000, // 5 minutes
            gcTime: 10 * 60 * 1000, // 10 minutes
            retry: (failureCount, error) => {
              // Type-cast the error since it could be any error type
              const axiosError = error as AxiosError;

              // Don't retry for client errors (4xx)
              if (
                axiosError.response?.status &&
                axiosError.response?.status >= 400 &&
                axiosError.response?.status < 500
              ) {
                return false;
              }

              // For server errors or network issues, retry up to 2 times
              return failureCount < 2;
            },
          },
          mutations: {
            retry: false, // Don't retry mutations by default
          },
        },
      }),
  );

  // Set the global reference
  queryClient = client;

  return <QueryClientProvider client={client}>{children}</QueryClientProvider>;
}

