import { render, screen, fireEvent } from "@testing-library/react";
import { describe, it, expect, vi, beforeEach } from "vitest";
import PromptTextareaWithCaption from "../index";

// Mock the useImageCaption hook
const mockGenerateCaption = vi.fn();
const mockUseImageCaption = {
  generateCaption: mockGenerateCaption,
  isLoading: false,
  isError: false,
  caption: "",
};

vi.mock("@/hooks/api/useImageCaption", () => ({
  "useImageCaption": () => mockUseImageCaption,
}));

// Mock Next.js Image component
vi.mock("next/image", () => ({
    // eslint-disable-next-line
  default: ({ src, alt, ...props }: any) => <img src={src} alt={alt} {...props} />,
}));

describe("PromptTextareaWithCaption", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockUseImageCaption.isLoading = false;
    mockUseImageCaption.isError = false;
    mockUseImageCaption.caption = "";
  });

  describe("Image filtering logic (commit changes)", () => {
    it("should filter out empty and whitespace-only images from imageUrl", () => {
      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl="  "
          multipleImages={["valid-image.jpg"]}
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      fireEvent.click(button);

      expect(mockGenerateCaption).toHaveBeenCalledWith(
        ["valid-image.jpg"],
        "TEST_FEATURE",
        "Help me to improve this prompt: test prompt"
      );
    });

    it("should filter out empty and whitespace-only images from multipleImages", () => {
      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl="valid-main-image.jpg"
          multipleImages={["valid-image.jpg", "", "  ", "another-valid.jpg"]}
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      fireEvent.click(button);

      expect(mockGenerateCaption).toHaveBeenCalledWith(
        ["valid-main-image.jpg", "valid-image.jpg", "another-valid.jpg"],
        "TEST_FEATURE",
        "Help me to improve this prompt: test prompt"
      );
    });

    it("should handle case with no valid images", () => {
      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl=""
          multipleImages={["", "  ", null as never]}
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      fireEvent.click(button);

      expect(mockGenerateCaption).toHaveBeenCalledWith(
        [],
        "TEST_FEATURE",
        "Help me to improve this prompt: test prompt"
      );
    });
  });

  describe("Button disabled state logic (commit changes)", () => {
    it("should enable button when prompt is empty but valid images exist", () => {
      render(
        <PromptTextareaWithCaption
          prompt=""
          imageUrl="valid-image.jpg"
          multipleImages={[]}
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      expect(button).not.toBeDisabled();
    });

    it("should enable button when prompt has only whitespace but valid images exist", () => {
      render(
        <PromptTextareaWithCaption
          prompt="   "
          imageUrl=""
          multipleImages={["valid-image.jpg"]}
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      expect(button).not.toBeDisabled();
    });

    it("should enable button when both prompt and valid images exist", () => {
      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl="valid-image.jpg"
          multipleImages={["another-image.jpg"]}
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      expect(button).not.toBeDisabled();
    });

    it("should disable button when prompt is empty/whitespace and no valid images exist", () => {
      render(
        <PromptTextareaWithCaption
          prompt="  "
          imageUrl=""
          multipleImages={["", "  "]}
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      expect(button).toBeDisabled();
    });

    it("should disable button when loading", () => {
      mockUseImageCaption.isLoading = true;

      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl="valid-image.jpg"
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      expect(button).toBeDisabled();
    });

    it("should enable button with valid prompt even without images", () => {
      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl=""
          multipleImages={[]}
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      expect(button).not.toBeDisabled();
    });
  });

  describe("Click handler behavior (commit changes)", () => {
    it("should call generateCaption with correct parameters when clicked", () => {
      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl="main-image.jpg"
          multipleImages={["image1.jpg", "image2.jpg"]}
          featureType="SKETCH_TO_RENDER"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      fireEvent.click(button);

      expect(mockGenerateCaption).toHaveBeenCalledWith(
        ["main-image.jpg", "image1.jpg", "image2.jpg"],
        "SKETCH_TO_RENDER",
        "Help me to improve this prompt: test prompt"
      );
    });

    it("should format prompt correctly with empty prompt", () => {
      render(
        <PromptTextareaWithCaption
          prompt=""
          imageUrl="valid-image.jpg"
          featureType="TEST_FEATURE"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      fireEvent.click(button);

      expect(mockGenerateCaption).toHaveBeenCalledWith(
        ["valid-image.jpg"],
        "TEST_FEATURE",
        "Help me to improve this prompt: "
      );
    });

    it("should use default feature type when not provided", () => {
      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl="valid-image.jpg"
        />
      );

      const button = screen.getByRole("button", { name: /prompt assist/i });
      fireEvent.click(button);

      expect(mockGenerateCaption).toHaveBeenCalledWith(
        ["valid-image.jpg"],
        "VIRTUAL_TRIAL",
        "Help me to improve this prompt: test prompt"
      );
    });
  });

  describe("Component rendering", () => {
    it("should render textarea with correct value", () => {
      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          title="Test Title"
          placeholder="Test placeholder"
        />
      );

      const textarea = screen.getByRole("textbox");
      expect(textarea).toHaveValue("test prompt");
      expect(screen.getByText("Test Title")).toBeInTheDocument();
      expect(textarea).toHaveAttribute("placeholder", "Test placeholder");
    });

    it("should show loading state in button", () => {
      mockUseImageCaption.isLoading = true;

      render(
        <PromptTextareaWithCaption
          prompt="test prompt"
          imageUrl="valid-image.jpg"
        />
      );

      expect(screen.getByText("Prompt Assist")).toBeInTheDocument();
      // The loading spinner should be present (Loader component)
      const button = screen.getByRole("button", { name: /prompt assist/i });
      expect(button).toBeInTheDocument();
    });

    it("should update internal prompt when external prompt changes", () => {
      const { rerender } = render(
        <PromptTextareaWithCaption prompt="initial prompt" />
      );

      const textarea = screen.getByRole("textbox");
      expect(textarea).toHaveValue("initial prompt");

      rerender(<PromptTextareaWithCaption prompt="updated prompt" />);
      expect(textarea).toHaveValue("updated prompt");
    });

    it("should call onPromptChange when textarea value changes", () => {
      const mockOnPromptChange = vi.fn();

      render(
        <PromptTextareaWithCaption
          prompt="initial"
          onPromptChange={mockOnPromptChange}
        />
      );

      const textarea = screen.getByRole("textbox");
      fireEvent.change(textarea, { target: { value: "new value" } });

      expect(mockOnPromptChange).toHaveBeenCalledWith("new value");
    });

    it("should update prompt when caption is received", () => {
      const mockOnPromptChange = vi.fn();
      mockUseImageCaption.caption = "Generated caption";

      render(
        <PromptTextareaWithCaption
          prompt="initial"
          onPromptChange={mockOnPromptChange}
        />
      );

      expect(mockOnPromptChange).toHaveBeenCalledWith("Generated caption");
    });
  });
});

