import React from "react";
import { render, screen, fireEvent } from "@testing-library/react";
import ImageCard from "..";
import { describe, it, expect, vi } from "vitest";

// Mock next/image to render a normal img element
vi.mock("next/image", () => ({
  __esModule: true,
  default: (props: any) => {
    // eslint-disable-next-line @next/next/no-img-element
    return <img {...props} alt={props.alt} />;
  },
}));

describe("ImageCard", () => {
  const imageUrl = "/test-image.jpg";
  const altText = "Test Image";
  const onDownload = vi.fn();
  const onImageClick = vi.fn();

  it("renders the image with alt text", () => {
    render(<ImageCard imageUrl={imageUrl} altText={altText} onDownload={onDownload} />);
    const image = screen.getByAltText(altText);
    expect(image).toBeInTheDocument();
    expect(image).toHaveAttribute("src", imageUrl);
  });

  it("calls onDownload when download button is clicked", () => {
    render(<ImageCard imageUrl={imageUrl} altText={altText} onDownload={onDownload} />);
    const downloadButton = screen.getByLabelText("Download image");
    fireEvent.click(downloadButton);
    expect(onDownload).toHaveBeenCalledTimes(1);
  });

  it("calls onImageClick when image is clicked", () => {
    render(
      <ImageCard
        imageUrl={imageUrl}
        altText={altText}
        onDownload={onDownload}
        onImageClick={onImageClick}
      />,
    );
    const image = screen.getByAltText(altText);
    fireEvent.click(image);
    expect(onImageClick).toHaveBeenCalledTimes(1);
  });

  it("does not render the maximize button if onImageClick is not provided", () => {
    render(<ImageCard imageUrl={imageUrl} altText={altText} onDownload={onDownload} />);
    const maximizeButtons = screen.queryByLabelText("View full image");
    expect(maximizeButtons).not.toBeInTheDocument();
  });
});

"use client";

import React, { useState } from "react";
import { useGetSubscriptionInfo } from "@/hooks/api/useGetSubscriptionInfo";
import { useRouter } from "next/navigation";
import Image from "next/image";
import { Button } from "@/components/ui/button";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { Download, Maximize, Heart, ImageIcon, Search, Crown } from "lucide-react";
import { FeedbackActionButton } from "@/components/FeedbackActionButton";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { ModalHighResDownload } from "../ModalHighResDownload";
import { BaseModal } from "../BaseModal";
import SpinnerLoader from "../SpinnerLoader";
import { cn } from "@/lib/utils";
import { useImageUpscale } from "@/hooks/api/useDownloadUpscale";
import { toast } from "sonner";

interface ImageCardProps {
  imageUrl: string;
  altText: string;
  onDownload: (event: React.MouseEvent<HTMLButtonElement>) => void;
  onDownloadSvg: (event: React.MouseEvent<HTMLButtonElement>) => void;
  className?: string;
  onImageClick?: () => void;
  onSaveToLibrary?: (event: React.MouseEvent<HTMLButtonElement>) => void;
  isSaved?: boolean; // Indicates if the image is already saved to library

  // Feedback related props
  taskId?: string;
  liked?: boolean | null;
  onLike?: (event: React.MouseEvent) => void;
  onDislike?: (event: React.MouseEvent) => void;
  comment?: string | null;
  children?: React.ReactNode;
}

const ImageCard: React.FC<ImageCardProps> = ({
  imageUrl,
  altText,
  onDownload,
  onDownloadSvg,
  className,
  onImageClick,
  onSaveToLibrary,
  isSaved = false,
  liked,
  onLike,
  onDislike,
  children,
}) => {
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [isModalHighResOpen, setIsModalHighResOpen] = useState(false);
  const [clickedUpscale, setClickedUpscale] = useState<"2k" | "4k" | null>(null);
  const router = useRouter();

  const { data: subscriptionInfo } = useGetSubscriptionInfo();
  const { mutate, isPending } = useImageUpscale();
  const plan = subscriptionInfo?.data?.plan;

  const handleUpgrade = (e: React.MouseEvent) => {
    e.stopPropagation();
    // Logic to redirect to upgrade page or open upgrade modal
    router.push("/account#subscription-plan");
  };
  const handleCloseUpgradeModal = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsModalHighResOpen(false);
  };
  const handleDownloadHighRes = (e: React.MouseEvent, image: string, scale: "2k" | "4k") => {
    e.stopPropagation();
    mutate(
      {
        image,
        upscale_size: scale,
      },
      {
        onSuccess: async (data) => {
          if (data && data[0]) {
            try {
              const response = await fetch(data[0]);
              const blob = await response.blob();
              const blobUrl = URL.createObjectURL(blob);
              const link = document.createElement("a");
              link.href = blobUrl;
              link.download = `upscaled-${scale}-${Date.now()}.png`;
              document.body.appendChild(link);
              link.click();
              document.body.removeChild(link);
              URL.revokeObjectURL(blobUrl);

              // Save to localStorage based on scale
              const storageKey = scale === "2k" ? "downloaded2k" : "downloaded4k";
              const existingDownloads = JSON.parse(localStorage.getItem(storageKey) || "[]");
              existingDownloads.push(data[0]);
              localStorage.setItem(storageKey, JSON.stringify(existingDownloads));

              // Show success
              toast.success(`${scale.toUpperCase()} image saved to Asset Library!`);
            } catch (error) {
              console.error("Failed to download image:", error);
              toast.error(`${scale.toUpperCase()} image upscaling failed`);
            }
          }
        },
      },
    );
  };

  return (
    <div className="border border-light rounded-lg shadow-sm overflow-hidden">
      <div
        className={`relative w-full h-auto group bg-muted/20 ${className ?? ""} ${
          children ? "overflow-visible" : "overflow-hidden"
        }`}
      >
        <div
          role={onImageClick ? "button" : undefined}
          tabIndex={onImageClick ? 0 : undefined}
          onClick={(e) => {
            if (onImageClick) {
              e.stopPropagation();
              onImageClick();
            }
          }}
          onKeyDown={(e) => {
            if (onImageClick && (e.key === "Enter" || e.key === " ")) {
              e.preventDefault();
              e.stopPropagation();
              onImageClick();
            }
          }}
        >
          <Image
            src={imageUrl}
            alt={altText}
            width={0}
            height={0}
            sizes="100vw"
            style={{ width: "100%", height: "auto" }}
            className={`bg-muted/20 z-2 ${onImageClick ? "cursor-pointer" : ""}`}
            unoptimized={true}
            crossOrigin="anonymous"
          />
        </div>
        <div className="absolute top-2 right-2 flex flex-col items-end space-y-1.5 group-hover:opacity-100 transition-opacity duration-200 z-10">
          {/* Save to Library Button */}
          {onSaveToLibrary && (
            <TooltipProvider>
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    variant="secondary"
                    size="icon"
                    className={`bg-background/80 hover:bg-background focus:opacity-100 ${
                      isSaved ? "bg-primary text-primary-foreground" : ""
                    }`}
                    onClick={(e) => {
                      e.stopPropagation();
                      if (!isSaved) {
                        onSaveToLibrary(e);
                      }
                    }}
                    disabled={isSaved}
                    aria-label={isSaved ? "Saved to library" : "Save to library"}
                  >
                    <Heart className={`h-4 w-4 ${isSaved ? "fill-current" : ""}`} />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>
                  <p>{isSaved ? "Saved to Library" : "Save to Library"}</p>
                </TooltipContent>
              </Tooltip>
            </TooltipProvider>
          )}

          {/* Download Button */}
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <DropdownMenu open={isDropdownOpen} onOpenChange={setIsDropdownOpen}>
                  <DropdownMenuTrigger asChild className="p-0">
                    <Button
                      variant="secondary"
                      size="icon"
                      className="bg-background/80 hover:bg-gray-200 focus:opacity-100"
                      aria-label="Download image"
                    >
                      <Download className="h-4 w-4" />
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end" className="w-[210px]">
                    <DropdownMenuItem
                      className={"cursor-pointer hover:bg-gray-200 px-1 py-2"}
                      onClick={(e) => {
                        e.stopPropagation();
                        setIsDropdownOpen(false);
                        onDownload(e as unknown as React.MouseEvent<HTMLButtonElement>);
                      }}
                    >
                      <ImageIcon className="h-4 w-4 mr-2" />
                      Download HD
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      className={cn(
                        "cursor-pointer hover:bg-gray-200 px-1 py-2",
                        plan?.includes("FREE") || plan === "DESIGNER" ? "opacity-50" : "",
                      )}
                      onClick={(e) => {
                        e.stopPropagation();
                        e.preventDefault();

                        setIsDropdownOpen(false);
                        setClickedUpscale("2k");
                        if (plan?.includes("FREE") || plan === "DESIGNER") {
                          setIsModalHighResOpen(true);
                          return;
                        } else {
                          handleDownloadHighRes(e, imageUrl, "2k");
                          //  onDownload(e as unknown as React.MouseEvent<HTMLButtonElement>);
                        }
                      }}
                    >
                      <div className="bg-yellow-500 rounded-full p-1">
                        <Crown className="h-4 w-4 text-white" />
                      </div>
                      Upscale to 2k Resolution
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      className={cn(
                        "cursor-pointer hover:bg-gray-200 px-1 py-2",
                        plan?.includes("FREE") || plan === "DESIGNER" || plan === "PRO"
                          ? "opacity-50"
                          : "",
                      )}
                      onClick={(e) => {
                        e.stopPropagation();
                        e.preventDefault();
                        setIsDropdownOpen(false);
                        setClickedUpscale("4k");

                        if (plan?.includes("FREE") || plan === "DESIGNER" || plan === "PRO") {
                          setIsModalHighResOpen(true);
                          return;
                        } else {
                          handleDownloadHighRes(e, imageUrl, "4k");
                          //onDownload(e as unknown as React.MouseEvent<HTMLButtonElement>);
                        }
                      }}
                    >
                      <div className="bg-yellow-500 rounded-full p-1">
                        <Crown className="h-4 w-4 text-white" />
                      </div>
                      Upscale to 4k Resolution
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      className="cursor-pointer"
                      onClick={(e) => {
                        e.stopPropagation();
                        setIsDropdownOpen(false);
                        onDownloadSvg(e as unknown as React.MouseEvent<HTMLButtonElement>);
                      }}
                    >
                      <Download className="h-4 w-4 mr-2" />
                      Download as SVG
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </TooltipTrigger>
              <TooltipContent>
                <p>Download Image</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>

          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  variant="secondary"
                  size="icon"
                  className="bg-background/80 hover:bg-background focus:opacity-100"
                  aria-label="Search with Google Lens"
                  onClick={(e) => {
                    e.stopPropagation();
                    const lensUrl = `https://lens.google.com/uploadbyurl?url=${encodeURIComponent(
                      imageUrl,
                    )}`;
                    window.open(lensUrl, "_blank");
                  }}
                >
                  <Search className="h-4 w-4" />
                </Button>
              </TooltipTrigger>
              <TooltipContent>
                <p>Search with Google Lens</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>

          {/* View Full Image Button */}
          {onImageClick && (
            <TooltipProvider>
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    variant="secondary"
                    size="icon"
                    className="bg-background/80 hover:bg-background focus:opacity-100"
                    onClick={(e) => {
                      e.stopPropagation();
                      onImageClick();
                    }}
                    aria-label="View full image"
                  >
                    <Maximize className="h-4 w-4" />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>
                  <p>View Full Image</p>
                </TooltipContent>
              </Tooltip>
            </TooltipProvider>
          )}

          {/* Feedback Action Button */}
          {onLike && onDislike && (
            <div
              className="bg-transparent"
              onClick={(e) => e.stopPropagation()}
              onKeyDown={(e) => e.stopPropagation()}
            >
              <FeedbackActionButton
                liked={liked}
                onLike={(e) => {
                  e.stopPropagation();
                  onLike(e);
                }}
                onDislike={(e) => {
                  e.stopPropagation();
                  onDislike(e);
                }}
              />
            </div>
          )}
        </div>
        {children && <div className="p-3 border-t border-light bg-background">{children}</div>}
        <ModalHighResDownload isOpen={isModalHighResOpen} onOpenChange={setIsModalHighResOpen}>
          <h2 className="font-semibold text-xl mb-8">
            {`This is a premium feature. Please upgrade your plan to ${
              clickedUpscale === "2k" ? "Pro" : "Pro +"
            }`}
          </h2>
          <div className="flex justify-center space-x-4">
            <Button variant="outline" onClick={handleCloseUpgradeModal}>
              Cancel
            </Button>
            <Button variant="default" onClick={handleUpgrade}>
              Upgrade
            </Button>
          </div>
        </ModalHighResDownload>
        <BaseModal isOpen={isPending} onOpenChange={() => {}} title="Upscaling Image">
          <div className="flex flex-col items-center justify-center gap-4 py-8">
            <SpinnerLoader size={48} />
            <p className="text-muted-foreground">Please wait while we upscale your image...</p>
          </div>
        </BaseModal>
      </div>
    </div>
  );
};

export default ImageCard;

