import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import "@testing-library/jest-dom";
import { GeneratedImageGallery } from "../index";

describe("GeneratedImageGallery", () => {
  const mockImages = ["data:image/png;base64,fake-image-1", "data:image/png;base64,fake-image-2"];

  it("renders loading state correctly", () => {
    render(
      <GeneratedImageGallery
        images={[]}
        isLoading={true}
        title="Test Gallery"
        emptyStateMessage="No images"
      />,
    );
    expect(screen.getByText("Loading images...")).toBeInTheDocument();
  });

  it("renders empty state message when no images", () => {
    const emptyMessage = "No images available";
    render(
      <GeneratedImageGallery
        images={[]}
        isLoading={false}
        title="Test Gallery"
        emptyStateMessage={emptyMessage}
      />,
    );
    expect(screen.getByText(emptyMessage)).toBeInTheDocument();
  });

  it("renders images when provided", () => {
    render(
      <GeneratedImageGallery
        images={mockImages}
        isLoading={false}
        title="Test Gallery"
        emptyStateMessage="No images"
      />,
    );
    const images = screen.getAllByRole("img");
    expect(images).toHaveLength(mockImages.length);
    images.forEach((img, index) => {
      expect(img).toHaveAttribute("src", mockImages[index]);
    });
  });

  it("renders title correctly", () => {
    const title = "No images";
    render(
      <GeneratedImageGallery
        images={[]}
        isLoading={false}
        title={title}
        emptyStateMessage="No images"
      />,
    );
    expect(screen.getByText(title)).toBeInTheDocument();
  });

  it("renders with custom grid columns class", () => {
    const customGridCols = "grid-cols-1 md:grid-cols-3";
    render(
      <GeneratedImageGallery
        images={mockImages}
        isLoading={false}
        title="Test Gallery"
        emptyStateMessage="No images"
        gridCols={customGridCols}
      />,
    );
    const grid = screen.getByTestId("generated-images-grid");
    expect(grid).toHaveClass(customGridCols);
  });
});

"use client";

import React, { useState, useMemo, useRef, useEffect } from "react";
// import AssetUploadModal from "../asset-library/AssetUploadModal";
import ImageCard from "../ImageCard";
import FeedbackCommentModal from "../FeedbackCommentModal";
import { Button } from "@/components/ui/button";
import { Download, Heart, Loader2, Sparkles, Crown } from "lucide-react";
import { useTaskId } from "@/hooks/useTaskId";
import { useTaskIdChanges } from "@/hooks/useTaskIdChanges";
import Link from "next/link";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { useAssetLibraryStore } from "@/store/assetLibraryStore";
import { useFeedbackStore, useFetchFeedbackData } from "@/store/feedbackStore";
import { useSavedAssetStore } from "@/store/savedAssetStore";
import { useFoldersQuery } from "@/hooks/api/assets/useAssetQueries";
import { useGetSubscriptionInfo } from "@/hooks/api/useGetSubscriptionInfo";
import { useCardDownload } from "@/hooks/useCardDownload";
import { TooltipProvider, Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { FeedbackActionButton } from "../FeedbackActionButton";
import { Star } from "lucide-react";
import { TooltipArrow } from "@radix-ui/react-tooltip";
import { handleCopy, handleDownloadImage } from "@/lib/utils";
import { RefineVariationDialog } from "../seamless-pattern-studio/RefineVariationModal";
import AssetUploadModalV2 from "../asset-library/AssetUploadModalV2";

import { useRouter } from "next/navigation";
import { cn } from "@/lib/utils";
import { ModalHighResDownload } from "../ModalHighResDownload";
import { BaseModal } from "../BaseModal";
import SpinnerLoader from "../SpinnerLoader";
import { useVideoDownloadHighRes } from "@/hooks/api/useVideoDownloadHighRes";
import AssetUploadModal from "../asset-library/AssetUploadModal";
import { useAddRating } from "@/hooks/api/print-studio/rating/useAddRating";
import { useRefinePrompt } from "@/store/useRefinePrompt";
import { useGetRatings } from "@/hooks/api/print-studio/rating/useGetRatings";
import { useQueryClient } from "@tanstack/react-query";
import { SEAMLESS_PATTERN_STUDIO_GENERATED_IMAGES } from "@/lib/constants";
import { useFeedbackActions } from "@/hooks/useFeedbackActions";

interface GeneratedImageGalleryProps {
  images: string[];
  isLoading?: boolean;
  title?: string;
  emptyStateMessage?: any;
  loadingMessage?: string;
  imageIcon?: React.ReactNode;
  enableModalView?: boolean;
  gridCols?: string;
  isError?: boolean;
  enableSaveToLibrary?: boolean; // New prop to enable save functionality
  isVideo?: boolean;
  showChildren?: boolean;
  selectedFolderName?: string;
  folderId?: number | null;
  isUsingV2AssetUpload?: boolean;
  onApplyRefineVariation?: (index?: number) => void;
  collectionId?: string;
}

export const GeneratedImageGallery: React.FC<GeneratedImageGalleryProps> = ({
  images,
  isLoading = false,
  title,
  emptyStateMessage = "No images to display.",
  loadingMessage = "Loading images...",
  imageIcon,
  enableModalView = true,
  isError = false,
  gridCols = "grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5",
  enableSaveToLibrary = false,
  isVideo = false,
  showChildren = false,
  selectedFolderName,
  folderId,
  isUsingV2AssetUpload = false,
  onApplyRefineVariation,
  collectionId,
}) => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [imageRatings, setImageRatings] = useState<Record<string, number>>({});
  const [isRefineVariationModalOpen, setIsRefineVariationModalOpen] = useState(false);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const { setRefinePrompt } = useRefinePrompt();
  const [isModalHighResOpen, setIsModalHighResOpen] = useState(false);
  const [clickedVideoQuality, setClickedVideoQuality] = useState<"1080p" | "4k" | null>(null);

  // Get task ID from the context hook
  const { taskId, pageType } = useTaskId();

  // Feedback state
  const {
    feedbackState,
    commentModalOpen,
    setCommentModalOpen,
    activeImage,
    setActiveImage,
    handleLike,
    handleDislike,
    handleSaveComment,
  } = useFeedbackActions({ taskId });

  // Get store hooks
  const { initializeImagesForTask } = useFeedbackStore();
  const { savedAssetsByTask, markAsSaved, clearTaskAssets } = useSavedAssetStore();
  const { downloadHighRes, isPending } = useVideoDownloadHighRes();
  const { mutate: addRating } = useAddRating();
  const { data: listOfRatings } = useGetRatings(showChildren);
  const { isUploadModalOpen, openUploadModal, uploadModalInitialData, closeUploadModal } =
    useAssetLibraryStore();
  const queryClient = useQueryClient();

  const { data: foldersData } = useFoldersQuery();
  const { data: subscriptionInfo } = useGetSubscriptionInfo();

  const router = useRouter();

  const plan = subscriptionInfo?.data?.plan;

  // Initialize feedback state for images using the store
  useFetchFeedbackData(taskId || "", images);

  // Feedback state initialization is handled by useFetchFeedbackData,
  // so we do not need a separate effect here to avoid duplicate initialization.

  // Use the task ID changes hook to react to changes in task ID
  useTaskIdChanges((newTaskId, oldTaskId) => {
    if (newTaskId && images.length > 0) {
      // Re-initialize feedback state when task ID changes
      initializeImagesForTask(newTaskId, images);
      console.log(
        `Task ID changed to ${newTaskId}, re-initializing feedback state for ${images.length} images`,
      );
    }

    // Clear saved assets for the old task ID to prevent stale state
    if (oldTaskId) {
      clearTaskAssets(oldTaskId);
    }
  }, pageType);

  // Local saved asset state derived from the store
  const savedAssetState = useMemo(() => {
    if (!taskId) return {};
    return savedAssetsByTask[taskId] || {};
  }, [taskId, savedAssetsByTask]);

  // Card download handler (SVG conversion + HD download)
  const { handleCardDownloadClick, isPendingConvertSvg } = useCardDownload({
    taskId,
    savedAssetState,
  });

  // Use refs to preserve the taskId and savedAssetState across async operations
  const taskIdRef = useRef(taskId);

  useEffect(() => {
    taskIdRef.current = taskId;
  }, [taskId]);

  useEffect(() => {
    setRefinePrompt("");
  }, [isRefineVariationModalOpen]);

  // Get stored results from localStorage
  const stored =
    typeof window !== "undefined"
      ? localStorage.getItem(SEAMLESS_PATTERN_STUDIO_GENERATED_IMAGES)
      : null;
  const storedResults = stored ? JSON.parse(stored) : [];

  const defaultFolderId = useMemo(() => {
    if (!foldersData) return undefined;
    const designsFolder = foldersData.find((f) => f.name === "Designs");
    if (designsFolder) return designsFolder.id;
    const generatedFolder = foldersData.find((f) => f.name === "Generated");
    if (generatedFolder) return generatedFolder.id;
    const firstFolder = foldersData.find((f) => !f.is_system && f.name !== "All Assets");
    return firstFolder?.id;
  }, [foldersData]);

  const handleImageClick = (imageUrl: string) => {
    if (enableModalView) {
      setSelectedImage(imageUrl);
      setIsModalOpen(true);
    }
  };

  const handleDownloadHighRes = (
    e: React.MouseEvent,
    video_file_url: string,
    scale: "1080p" | "4k",
  ) => {
    downloadHighRes(e, video_file_url, scale);
  };
  const handleUpgrade = (e: React.MouseEvent) => {
    e.stopPropagation();
    // Logic to redirect to upgrade page or open upgrade modal
    router.push("/account#subscription-plan");
  };
  const handleCloseUpgradeModal = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsModalHighResOpen(false);
  };

  const handleTriggerSaveToLibrary = (imageUrl: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const defaultName = `Generated Image ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}`;
    setSelectedImage(imageUrl);
    openUploadModal("asset", {
      imageUrl: imageUrl,
      name: defaultName,
    });
  };

  const show1080PBadge = plan?.includes("FREE");
  const isButton1080Disabled = plan?.includes("FREE");
  const isButton4kDisabled = plan?.includes("FREE") || plan === "DESIGNER";

  // Handle star rating
  const handleStarRating = (imageUrl: string, rating: number) => {
    if (rating <= 3) {
      setActiveImage(imageUrl);
      setCommentModalOpen(true);
    }
    addRating(
      { image_url: imageUrl, rating: rating },
      {
        onSuccess: () => {
          console.log(`Rating of ${rating} added for image ${imageUrl}`);
        },
        onError: (error) => {
          console.error("Error adding rating:", error);
        },
      },
    );
    setImageRatings((prev) => ({
      ...prev,
      [imageUrl]: rating,
    }));
  };

  useEffect(() => {
    if (listOfRatings && listOfRatings.length > 0) {
      const ratingsMap: Record<string, number> = {};
      listOfRatings.forEach((ratingItem: any) => {
        ratingsMap[ratingItem.image_url] = ratingItem.rating;
      });
      setImageRatings(ratingsMap);
    }
  }, [listOfRatings]);

  if (isLoading || isPendingConvertSvg) {
    return (
      <div className="flex flex-col items-center justify-center h-64">
        <div className="flex flex-row items-center justify-center mb-2">
          <p className="text-lg text-muted-foreground">
            {isLoading ? `${loadingMessage}` : "Converting to SVG. Dont block your browser pop up"}
          </p>{" "}
          <Loader2 className="h-8 w-8 animate-spin text-primary ml-2" />
        </div>
        <p className="text-lg">Please do not switch features or close your browser</p>
        {isPendingConvertSvg && (
          <p>
            SVG outputs are automatically saved in your <strong>Asset Library</strong>
          </p>
        )}
      </div>
    );
  }
  if (!images || images.length === 0 || isError) {
    return (
      <div id="results-section">
        {subscriptionInfo !== undefined &&
          (subscriptionInfo.data.remaining_credits > 0 ||
            (subscriptionInfo.data.remaining_top_up_credits || 0) > 0) && (
            <p className="text-gray-500 text-block mb-4">
              Your remaining credits:{" "}
              {subscriptionInfo.data.remaining_credits +
                (subscriptionInfo.data.remaining_top_up_credits || 0)}
            </p>
          )}
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-muted rounded-lg p-4 text-center">
          {imageIcon && <div className="mb-4">{imageIcon}</div>}
          {emptyStateMessage?.message ? (
            <div>
              <p className="text-lg text-muted-foreground">{emptyStateMessage.message}</p>
              <Button asChild className="mt-2">
                <Link href="/account">Buy Credits</Link>
              </Button>
            </div>
          ) : emptyStateMessage ? (
            <p className="text-lg text-muted-foreground">{emptyStateMessage}</p>
          ) : (
            ""
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6" id="results-section">
      {title && <h2 className="text-2xl font-semibold tracking-tight mb-1">{title}</h2>}
      {subscriptionInfo !== undefined &&
        (subscriptionInfo.data.remaining_credits > 0 ||
          (subscriptionInfo.data.remaining_top_up_credits || 0) > 0) && (
          <p className="text-gray-500">
            Your remaining credits:{" "}
            {subscriptionInfo.data.remaining_credits +
              (subscriptionInfo.data.remaining_top_up_credits || 0)}
          </p>
        )}
      <div className={`grid ${gridCols} gap-4`} data-testid="generated-images-grid">
        {isVideo
          ? images.map((src) => {
              const isSaved = Boolean(taskId && savedAssetState[src]);

              return (
                <div key={src} className="w-full rounded-lg shadow-md relative">
                  <video
                    controls
                    style={{ height: "300px", width: "100%" }}
                    className="object-contain"
                  >
                    <source src={src} type="video/mp4" />
                    <track kind="captions" src="" label="English" />
                    Your browser does not support the video tag.
                  </video>
                  {/* Save to Library Button */}
                  <div className="absolute top-4 right-2 flex flex-col items-end space-y-1.5 group-hover:opacity-100 transition-opacity duration-200 z-10">
                    <TooltipProvider>
                      <Tooltip>
                        <TooltipTrigger asChild>
                          <Button
                            variant={isSaved ? "default" : "secondary"}
                            size="icon"
                            style={{
                              backgroundColor: isSaved ? "hsl(var(--primary))" : "",
                              color: isSaved ? "hsl(var(--primary-foreground))" : undefined,
                            }}
                            className={`!important transition-all duration-200 ${
                              isSaved
                                ? "!bg-primary !text-primary-foreground hover:!bg-primary/90 cursor-default"
                                : " hover:bg-background cursor-pointer"
                            }`}
                            onClick={(e) => {
                              console.log("src", src);
                              e.stopPropagation();
                              if (!isSaved) {
                                handleTriggerSaveToLibrary(src, e);
                              }
                            }}
                            aria-label={isSaved ? "Saved to library" : "Save to library"}
                          >
                            <Heart className={`h-4 w-4 ${isSaved ? "fill-current" : ""}`} />
                          </Button>
                        </TooltipTrigger>
                        <TooltipContent
                          className={`${
                            isSaved
                              ? "bg-primary text-white border-primary"
                              : "bg-white text-popover-foreground"
                          } text-sm font-light rounded-sm shadow-md p-0`}
                        >
                          <TooltipArrow className="fill-primary" />
                          <p
                            className={`px-2 py-1 rounded-sm ${
                              isSaved ? "text-white font-semibold" : "bg-primary text-white"
                            }`}
                          >
                            {isSaved ? "Saved to Library" : "Save to Library "}
                          </p>
                        </TooltipContent>
                      </Tooltip>
                    </TooltipProvider>
                  </div>
                  {/* Feedback Action Button */}
                  <div
                    className="bg-transparent absolute top-14.5 right-2"
                    onClick={(e) => e.stopPropagation()}
                    onKeyDown={(e) => e.stopPropagation()}
                  >
                    <FeedbackActionButton
                      liked={feedbackState[src]?.liked ?? undefined}
                      onLike={(e) => {
                        e.stopPropagation();
                        handleLike(src, e);
                      }}
                      onDislike={(e) => {
                        e.stopPropagation();
                        handleDislike(src, e);
                      }}
                    />
                  </div>
                  {show1080PBadge && (
                    <div
                      className={cn(
                        "cursor-pointer bg-gray-900 p-0.5 absolute font-light rounded-sm shadow-md top-25 right-2 w-14 h-6 text-center font-semibold",
                        isButton1080Disabled ? "opacity-50" : "",
                      )}
                      onClick={(e) => {
                        if (isButton1080Disabled) {
                          setClickedVideoQuality("1080p");
                          setIsModalHighResOpen(true);
                          return;
                        } else {
                          handleDownloadHighRes(e, src, "1080p");
                        }
                      }}
                    >
                      <div className="bg-white text-sm dark:text-gray-900 ">1080P</div>
                      <div className="absolute -right-4 -top-2 h-6 w-6 p-1 rounded-full text-center bg-yellow-500">
                        <Crown className="h-4 w-4 text-white " />
                      </div>
                    </div>
                  )}
                  <div
                    className={cn(
                      "cursor-pointer bg-gray-900 p-0.5 absolute font-light rounded-sm shadow-md right-2 w-14 h-9 text-center font-semibold",
                      show1080PBadge ? "top-33" : "top-25",
                      isButton4kDisabled ? "opacity-50" : "",
                    )}
                    onClick={(e) => {
                      if (isButton4kDisabled) {
                        setClickedVideoQuality("4k");
                        setIsModalHighResOpen(true);
                        return;
                      } else {
                        handleDownloadHighRes(e, src, "4k");
                      }
                    }}
                  >
                    <div className="bg-white text-sm dark:text-gray-900 h-5">4K</div>
                    <span className="text-white text-[8px] block">ULTRA HD</span>
                    <div className="absolute -right-4 -top-2 h-6 w-6 p-1 rounded-full text-center bg-yellow-500">
                      <Crown className="h-4 w-4 text-white" />
                    </div>
                  </div>
                  <ModalHighResDownload
                    isOpen={isModalHighResOpen}
                    onOpenChange={setIsModalHighResOpen}
                  >
                    <h2 className="font-semibold text-xl mb-8">
                      {`This is a premium feature. Please upgrade your plan to ${
                        plan?.includes("FREE")
                          ? clickedVideoQuality === "1080p"
                            ? "Designer plan"
                            : "Pro / Pro +"
                          : "Pro +"
                      }`}
                    </h2>
                    <div className="flex justify-center space-x-4">
                      <Button variant="outline" onClick={handleCloseUpgradeModal}>
                        Cancel
                      </Button>
                      <Button variant="default" onClick={handleUpgrade}>
                        Upgrade
                      </Button>
                    </div>
                  </ModalHighResDownload>
                  <BaseModal isOpen={isPending} onOpenChange={() => {}} title="Upscaling Video">
                    <div className="flex flex-col items-center justify-center gap-4 py-8">
                      <SpinnerLoader size={48} />
                      <p className="text-muted-foreground">
                        Please wait while we upscale your video...
                      </p>
                      <p>
                        Video downloads are automatically saved in your{" "}
                        <strong>Asset Library</strong>
                      </p>
                    </div>
                  </BaseModal>
                </div>
              );
            })
          : images?.map((src, index: number) => (
              <ImageCard
                key={src}
                imageUrl={src}
                altText={`Generated visual`}
                onDownload={(e: React.MouseEvent) => handleCardDownloadClick(src, e)}
                onDownloadSvg={(e: React.MouseEvent) => handleCardDownloadClick(src, e, true)}
                className="aspect-square"
                onImageClick={() => handleImageClick(src)}
                onSaveToLibrary={
                  enableSaveToLibrary
                    ? (e: React.MouseEvent) => handleTriggerSaveToLibrary(src, e)
                    : undefined
                }
                isSaved={Boolean(taskId && savedAssetState[src])}
                liked={taskId ? feedbackState[src]?.liked : undefined}
                onLike={taskId ? (e: React.MouseEvent) => handleLike(src, e) : undefined}
                onDislike={taskId ? (e: React.MouseEvent) => handleDislike(src, e) : undefined}
                comment={taskId ? feedbackState[src]?.comment : undefined}
              >
                {showChildren && (
                  <div className="" onClick={(e) => e.stopPropagation()}>
                    <div className="flex">
                      <div className="w-[85%]">
                        {/* <p className="text-gray-600 font-semibold">Floral Faces Cream</p> */}
                        <p className="text-gray-400">Rate this variation:</p>
                      </div>
                      <p>
                        <TooltipProvider>
                          <Tooltip>
                            <TooltipTrigger asChild>
                              <Sparkles
                                className="w-5 h-5 text-yellow-500 cursor-pointer"
                                onClick={(e) => {
                                  e.stopPropagation();
                                  // const index = images.indexOf(src);
                                  setActiveIndex(index);
                                  setIsRefineVariationModalOpen(true);
                                }}
                              />
                            </TooltipTrigger>
                            <TooltipContent>
                              <div className="cursor-pointer">View Prompt</div>
                            </TooltipContent>
                          </Tooltip>
                        </TooltipProvider>
                      </p>
                    </div>

                    <div className="flex items-center gap-1 mt-2">
                      {[1, 2, 3, 4, 5].map((star) => (
                        <button
                          key={star}
                          onClick={(e) => {
                            e.stopPropagation();
                            handleStarRating(src, star);
                          }}
                          className="p-0 bg-transparent border-none cursor-pointer hover:scale-110 transition-transform"
                        >
                          <Star
                            className={`w-5 h-5 transition-colors ${
                              star <= (imageRatings[src] || 0)
                                ? "fill-yellow-400 text-yellow-400"
                                : "text-gray-300 hover:text-yellow-300"
                            }`}
                          />
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </ImageCard>
            ))}
      </div>

      {enableModalView && selectedImage && (
        <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
          <DialogContent className="sm:max-w-[90vw] md:max-w-[70vw] lg:max-w-[60vw] xl:max-w-[50vw] p-0">
            <DialogHeader className="p-4 pb-0">
              <DialogTitle className="flex justify-between items-center">Preview</DialogTitle>
            </DialogHeader>
            <div className="p-4 pt-0 max-h-[80vh] overflow-y-auto">
              <img
                src={selectedImage}
                alt={`Selected generated visual`}
                className="w-full h-auto rounded-md object-contain"
              />
            </div>
            <DialogFooter className="p-4 pt-2 border-t">
              <Button
                onClick={() => handleDownloadImage(selectedImage)} // Direct call, no event needed
                variant="default"
                size="lg"
              >
                <Download className="mr-2 h-4 w-4" />
                Download
              </Button>
            </DialogFooter>
          </DialogContent>{" "}
        </Dialog>
      )}

      {showChildren && (
        <RefineVariationDialog
          open={isRefineVariationModalOpen}
          onOpenChange={(open) => {
            setIsRefineVariationModalOpen(open);
            if (!open) {
              setActiveIndex(null);
            }
          }}
          originalPrompt={
            activeIndex !== null && storedResults[activeIndex]
              ? storedResults[activeIndex].prompt_used || ""
              : ""
          }
          onUseAsBase={() => {
            const prompt =
              activeIndex !== null && storedResults[activeIndex]
                ? storedResults[activeIndex].prompt_used || ""
                : "";
            handleCopy(prompt || "Prompt copied");
            setRefinePrompt(prompt || "");
          }}
          onCancel={() => {
            setIsRefineVariationModalOpen(false);
            setActiveIndex(null);
          }}
          onApply={
            onApplyRefineVariation ? () => onApplyRefineVariation(activeIndex || 0) : undefined
          }
        />
      )}
      {/* Asset Upload Modal for Save to Library - connected to  Zustand store */}
      {enableSaveToLibrary && !isUsingV2AssetUpload && (
        <AssetUploadModal
          isOpen={isUploadModalOpen}
          isVideo={isVideo}
          canCreateFolder={true}
          onOpenChange={(isOpen) => {
            if (!isOpen) {
              closeUploadModal();
            }
          }}
          uploadType="asset"
          defaultFolderId={defaultFolderId}
          initialData={
            uploadModalInitialData
              ? {
                  source_image_url: uploadModalInitialData.imageUrl,
                  source_image_filename: uploadModalInitialData.name,
                }
              : undefined
          }
          onSuccess={(asset) => {
            // When asset is saved successfully, update the savedAssetStore
            if (taskId && uploadModalInitialData?.imageUrl && asset.id) {
              markAsSaved(taskId, uploadModalInitialData.imageUrl, asset.id);
            }
          }}
          source="generated"
        />
      )}
      {enableSaveToLibrary && isUsingV2AssetUpload && (
        <AssetUploadModalV2
          isOpen={isUploadModalOpen}
          onOpenChange={(isOpen) => {
            if (!isOpen) {
              closeUploadModal();
            }
          }}
          onSuccess={(asset) => {
            // When asset is saved successfully, update the savedAssetStore
            if (taskId && uploadModalInitialData?.imageUrl && asset?.data?.id) {
              markAsSaved(taskId, uploadModalInitialData.imageUrl, asset?.data?.id);
              queryClient.invalidateQueries({ queryKey: ["get-saved-images"] });
            }
          }}
          folderId={folderId || defaultFolderId || 1}
          folderName={selectedFolderName || ""}
          selectedImage={selectedImage || ""}
          collectionId={collectionId || ""}
        />
      )}

      {/* Feedback comment modal */}
      <FeedbackCommentModal
        isOpen={commentModalOpen}
        onClose={() => setCommentModalOpen(false)}
        taskId={taskId || ""}
        imageUrl={activeImage || ""}
        initialComment={feedbackState[activeImage || ""]?.comment || null}
        liked={feedbackState[activeImage || ""]?.liked || null}
        onSave={handleSaveComment}
        type={isVideo ? "video" : "image"}
      />
    </div>
  );
};

