import { useEffect, useState } from "react";

interface SubscriptionInfo {
  data?: {
    remaining_credits?: number;
    remaining_top_up_credits?: number;
  };
}

interface UseCreditSufficiencyProps {
  subscriptionInfo?: SubscriptionInfo;
  type: "video" | "image";
  numberOfItems: number;
  videoDuration?: number; // only used if type = "video"
}

export function useCreditSufficiency({
  subscriptionInfo,
  type,
  numberOfItems,
  videoDuration,
}: UseCreditSufficiencyProps) {
  const [isCreditSufficient, setIsCreditSufficient] = useState(false);

  useEffect(() => {
    if (!subscriptionInfo) return;

    const remaining = (subscriptionInfo.data?.remaining_credits ?? 0) + (subscriptionInfo.data?.remaining_top_up_credits ?? 0);
    let requiredCredits = 0;

    if (type === "video") {
      const costPerVideo = videoDuration === 5 ? 10 : 15;
      requiredCredits = numberOfItems * costPerVideo;
    } else if (type === "image") {
      requiredCredits = numberOfItems; // 1 credit per image
    }

    setIsCreditSufficient(remaining >= requiredCredits);
  }, [subscriptionInfo, type, numberOfItems, videoDuration]);

  return isCreditSufficient;
}

