import { render, screen, fireEvent } from "@testing-library/react";
import { describe, it, expect, vi, beforeEach } from "vitest";
import Sidebar from "../index";
import { SidebarProvider } from "@/components/ui/sidebar";
import React from "react";

// Mock next/navigation and next/image
vi.mock("next/navigation", () => ({
  usePathname: () => "/sketch",
}));
vi.mock("next/image", () => ({
  __esModule: true,
  default: (props: any) => <img {...props} />,
}));

// Mock the user info hook that uses React Query
vi.mock("@/hooks/api/core/useGetUserInfo", () => ({
  useGetUserInfo: () => ({
    data: {
      id: "test-user-id",
      username: "testuser",
      email: "test@example.com",
    },
    isLoading: false,
    error: null,
  }),
}));

// Mock useDecodeToken hook that uses next-auth
vi.mock("@/hooks/useDecodeToken", () => ({
  useDecodeToken: () => ({
    decodedToken: { sub: "test-user-id" },
    session: { accessToken: "test-token" },
    status: "authenticated",
    isLoading: false,
    isAuthenticated: true,
  }),
}));

// Mock localStorage
beforeEach(() => {
  vi.stubGlobal("localStorage", {
    getItem: vi.fn((key: string) => {
      if (key === "hasVisitedBefore") return "true";
      if (key === "userId") return "test-user-id";
      return null;
    }),
    setItem: vi.fn(),
    removeItem: vi.fn(),
    clear: vi.fn(),
  });
});

function renderWithProvider() {
  return render(
    <SidebarProvider>
      <Sidebar />
    </SidebarProvider>,
  );
}

describe("Sidebar", () => {
  it("renders sidebar navigation items", () => {
    renderWithProvider();
    // Check for actual navigation titles from the component
    expect(screen.getByText(/Design Agent/i)).toBeInTheDocument();
    expect(screen.getByText(/Product Design/i)).toBeInTheDocument();
    expect(screen.getByText(/Sketch to Render/i)).toBeInTheDocument();
    expect(screen.getByText(/Sketch Generator/i)).toBeInTheDocument();
    expect(screen.getByText(/Precise Editing/i)).toBeInTheDocument();
    expect(screen.getByText(/Prints & Seamless Patterns/i)).toBeInTheDocument();
  });

  it("shows navigation sections", () => {
    renderWithProvider();
    expect(screen.getByText(/Main/i)).toBeInTheDocument();
    expect(screen.getByText(/Design Tools/i)).toBeInTheDocument();
  });

  it("toggles sidebar open/close when button is clicked", () => {
    renderWithProvider();
    const toggleButton = screen.getByRole("button", { name: /collapse sidebar|expand sidebar/i });
    fireEvent.click(toggleButton);
    expect(toggleButton).toBeInTheDocument();
  });
});

